/**
 * @deprecated OverflowMenu is deprecated. Use Menu from @cascivo/components/menu instead.
 * OverflowMenu is kept for registry compatibility and will be removed in v4.
 */
'use client'
import { cn, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import type { ReactNode } from 'react'
import { Dropdown } from '../dropdown/dropdown'
import type { DropdownItem } from '../dropdown/dropdown'
import styles from './overflow-menu.module.css'

export interface OverflowMenuItem {
  label: string
  value: string
  icon?: ReactNode
  disabled?: boolean
  destructive?: boolean
}

export interface OverflowMenuProps {
  items: OverflowMenuItem[]
  onSelect?: (value: string) => void
  placement?: 'bottom-start' | 'bottom-end'
  ariaLabel?: string
  size?: 'sm' | 'md'
  disabled?: boolean
  className?: string
}

function KebabIcon() {
  return (
    <svg viewBox="0 0 16 16" width="16" height="16" fill="currentColor" aria-hidden="true">
      <circle cx="8" cy="3" r="1.5" />
      <circle cx="8" cy="8" r="1.5" />
      <circle cx="8" cy="13" r="1.5" />
    </svg>
  )
}

export function OverflowMenu({
  items,
  onSelect,
  placement = 'bottom-end',
  ariaLabel,
  size = 'md',
  disabled = false,
  className,
}: OverflowMenuProps) {
  useSignals()
  const resolvedAriaLabel = ariaLabel ?? t(builtin.overflowMenu.trigger)
  // Map to Dropdown's item shape. Destructive items carry a hidden marker span
  // inside the icon slot so CSS can target them via :has().
  const dropdownItems: DropdownItem[] = items.map((item) => {
    const mapped: DropdownItem = { label: item.label, value: item.value }
    if (item.disabled !== undefined) mapped.disabled = item.disabled
    if (item.destructive) {
      mapped.icon = (
        <>
          {item.icon}
          <span className={styles['destructive-flag']} aria-hidden="true" />
        </>
      )
    } else if (item.icon !== undefined) {
      mapped.icon = item.icon
    }
    return mapped
  })

  return (
    <div className={cn(styles['root'], className)}>
      <Dropdown
        items={dropdownItems}
        onSelect={(value) => onSelect?.(value)}
        placement={placement}
        trigger={
          <button
            type="button"
            className={styles['trigger']}
            data-size={size}
            disabled={disabled}
            aria-label={resolvedAriaLabel}
          >
            <KebabIcon />
          </button>
        }
      />
    </div>
  )
}

@layer cascivo.component {
  .root {
    display: inline-flex;
  }

  .trigger {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 0;
    color: var(--cascivo-color-text-muted);
    background-color: transparent;
    border: 1px solid transparent;
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    transition:
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      color var(--cascivo-duration-150) var(--cascivo-ease-out),
      box-shadow var(--cascivo-duration-150) var(--cascivo-ease-out);

    &[data-size='sm'] {
      inline-size: 2rem;
      block-size: 2rem;
    }

    &[data-size='md'] {
      inline-size: 2.5rem;
      block-size: 2.5rem;
    }

    &:hover:not(:disabled) {
      color: var(--cascivo-color-text);
      background-color: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
      pointer-events: none;
    }
  }

  /* Invisible marker rendered into the icon slot of destructive items. */
  .destructive-flag {
    display: none;
  }

  .root [role='menuitem']:has(.destructive-flag) {
    color: var(--cascivo-color-destructive);

    &:hover:not(:disabled),
    &:focus-visible {
      background-color: var(--cascivo-color-destructive-subtle);
    }

    /* Dropdown's icon wrapper sets a muted color; make it follow the item. */
    > span {
      color: inherit;
    }
  }

  /* Hide the icon wrapper when it only contains the marker (no real icon),
     so destructive items without icons align with the other items. */
  .root [role='menuitem'] > span:has(> .destructive-flag:only-child) {
    display: none;
  }
}
